#!/usr/bin/env node
'use strict';

var fs = require('fs');
var path = require('path');

var ROOT = path.join(__dirname, '..');
var CLAY_DIR = path.join(ROOT, 'src', 'pkjs', 'clay');
var PARTS_DIR = path.join(CLAY_DIR, 'parts');
var THEME_CSS_PATH = path.join(CLAY_DIR, 'theme.css');
var OUTPUT_PATH = path.join(ROOT, 'src', 'pkjs', 'custom-clay.js');

var HEADER = [
  '// Generated by scripts/build-custom-clay.js — edit src/pkjs/clay/ instead.',
  '',
].join('\n');

var PREAMBLE = [
  'module.exports = function () {',
  '  var clayConfig = this;',
  '  var userData = clayConfig.meta.userData || {};',
  '  var holidaySubdivisions = {};',
  '  var holidaySubdivisionsCatalog = {};',
  '  var subdivisionNameLookup = {};',
  '  var supportedCountryCodes = {};',
  '  var holidayCountryOptions = [{ label: \'Loading countries…\', value: \'\' }];',
  '  var NAGER_API_BASE = \'https://date.nager.at/api\';',
  '  var CLAY_COUNTRIES_CACHE_KEY = \'argus-clay-countries-v1\';',
  '  var CLAY_SUBDIVISIONS_CACHE_PREFIX = \'argus-clay-subdivisions-v2:\';',
].join('\n');

function readPartFiles() {
  if (!fs.existsSync(PARTS_DIR)) {
    throw new Error('Missing parts directory: ' + PARTS_DIR);
  }

  return fs.readdirSync(PARTS_DIR)
    .filter(function (name) {
      return name.endsWith('.js');
    })
    .sort()
    .map(function (name) {
      return fs.readFileSync(path.join(PARTS_DIR, name), 'utf8').trim();
    });
}

function minifyCss(source) {
  try {
    var CleanCSS = require('clean-css');
    var result = new CleanCSS({ level: 1 }).minify(source);
    if (result.errors && result.errors.length) {
      throw new Error(result.errors.join('; '));
    }
    return result.styles;
  } catch (err) {
    if (err.code === 'MODULE_NOT_FOUND') {
      console.warn('clean-css not installed; using unminified theme.css');
      return source.replace(/\s+/g, ' ').trim();
    }
    throw err;
  }
}

function minifyJs(source) {
  if (process.env.CLAY_MINIFY === '0') {
    return source;
  }

  try {
    var terser = require('terser');
    var result = terser.minify_sync(source, {
      compress: true,
      mangle: false,
      format: {
        comments: /^!/,
      },
    });
    if (result.error) {
      throw result.error;
    }
    return result.code;
  } catch (err) {
    if (err.code === 'MODULE_NOT_FOUND') {
      console.warn('terser not installed; skipping JS minification');
      return source;
    }
    throw err;
  }
}

function buildSource() {
  if (!fs.existsSync(THEME_CSS_PATH)) {
    throw new Error('Missing theme.css: ' + THEME_CSS_PATH);
  }

  var themeCss = minifyCss(fs.readFileSync(THEME_CSS_PATH, 'utf8'));
  var parts = readPartFiles();
  if (!parts.length) {
    throw new Error('No part files found in ' + PARTS_DIR);
  }

  var themeAssignment = '  var THEME_CSS = ' + JSON.stringify(themeCss) + ';';
  var body = parts.map(function (part) {
    return part.split('\n').map(function (line) {
      return line ? '  ' + line : line;
    }).join('\n');
  }).join('\n\n');

  return HEADER + PREAMBLE + '\n' + themeAssignment + '\n\n' + body + '\n};\n';
}

function main() {
  var source = buildSource();
  var output = minifyJs(source);
  fs.writeFileSync(OUTPUT_PATH, output, 'utf8');

  console.log('Wrote ' + path.relative(ROOT, OUTPUT_PATH));
  console.log('  output bytes:', Buffer.byteLength(output, 'utf8'));
  console.log('  minify:', process.env.CLAY_MINIFY === '0' ? 'off' : 'on (set CLAY_MINIFY=0 to disable)');
}

main();
